// Execução principal do processador de mensagens
try {
  const items = $input.all(); // Obtém todos os itens de entrada do nó anterior
  return processarMensagens(items);
} catch (error) {
  console.error('Erro na execução principal:', error);
  throw error;
}

/**
 * Processa um conjunto de itens, limpando suas mensagens
 * @param {Array} items - Array de objetos contendo mensagens para processamento
 * @return {Array} - Array de objetos com mensagens processadas
 */
function processarMensagens(items) {
  return items.map(item => {
    try {
      // Verifica se o item tem a estrutura esperada
      if (!item?.json?.Mensagem) {
        return item;
      }

      const original = item.json.Mensagem;
      let mensagem = original;

      // Converte objetos para string quando necessário
      if (typeof mensagem === 'object') {
        try {
          mensagem = JSON.stringify(mensagem);
        } catch (e) {
          console.error('Falha na conversão objeto-string:', e);
          return item;
        }
      }

      // Garante que é string
      if (typeof mensagem !== 'string') {
        mensagem = String(mensagem ?? '');
      }

      // Aplica o processo de limpeza na mensagem
      let mensagemLimpa = limparMensagem(mensagem);

      // Se por algum motivo ficar vazia, usa a original (fallback seguro)
      if (!mensagemLimpa || mensagemLimpa.length === 0) {
        mensagemLimpa = String(original ?? '').trim();
      }

      // Limita tamanho para não envenenar o LLM com texto absurdo
      const LIMITE_CHAR = 4000;
      if (mensagemLimpa.length > LIMITE_CHAR) {
        mensagemLimpa = mensagemLimpa.slice(mensagemLimpa.length - LIMITE_CHAR);
      }

      // Só atualiza o item se a mensagem limpa tiver conteúdo
      if (mensagemLimpa && mensagemLimpa.length > 0) {
        item.json.Mensagem = mensagemLimpa;
      }

      return { json: item.json };
    } catch (error) {
      console.error('Erro no processamento do item:', error);
      return item;
    }
  });
}

/**
 * Função para extrair o conteúdo principal de um texto excluindo partes irrelevantes
 * @param {string} str - Texto a ser processado
 * @return {string} - Texto com apenas as frases relevantes
 */
function extrairMensagemPrincipal(str) {
  // Divide o texto em frases utilizando pontuação como delimitador
  const frases = str.split(/(?<=[.!?])\s+/);

  return frases
    .map(frase => frase.trim())
    .filter(frase => {
      // Critérios para manter apenas frases relevantes
      return (
        frase.length > 0 &&
        !frase.includes('tool_calls') &&
        !frase.includes('invalid_tool_calls') &&
        !frase.match(/^[:\s\[\]{}]+$/)
      );
    })
    .join(' ');
}

/**
 * Remove caracteres de formatação e escapamento indesejados
 * @param {string} str - Texto para limpeza de caracteres
 * @return {string} - Texto sem caracteres especiais problemáticos
 */
function limparCaracteresEspeciais(str) {
  return str
    .replace(/\\\\[rnt]/g, ' ')           // Substitui sequências de escape por espaço
    .replace(/\\"/g, '')                  // Elimina aspas com escape
    .replace(/\\\\\\\\/g, '')             // Remove barras invertidas múltiplas
    .replace(/[\x00-\x1F\x7F-\x9F]/g, '') // Elimina caracteres de controle
    .replace(/\"+/g, '')                  // Retira sequências de aspas
    .replace(/[{}\[\]]/g, '')             // Remove símbolos de objetos/arrays
    .trim();
}

/**
 * Função principal que orquestra a limpeza completa de uma mensagem
 * @param {string} texto - Texto original a ser limpo
 * @return {string} - Texto limpo e processado
 */
function limparMensagem(texto) {
  // Verificação de tipo para garantir segurança
  if (typeof texto !== 'string') {
    return '';
  }

  let resultado = texto;

  // Etapa 0: curto-circuito se for claramente só JSONzão sem texto humano
  if (
    resultado.includes('{') &&
    resultado.includes('}') &&
    resultado.includes('"tool_calls"') &&
    !/[a-zA-ZÀ-ÿ]{3,}/.test(resultado) // quase sem texto "normal"
  ) {
    // Nesse caso deixa o próprio fluxo de fallback decidir depois
    return '';
  }

  // Etapa 1: Remove metadados técnicos
  resultado = removerMetadataTecnico(resultado);

  // Etapa 2: Extrai apenas as frases relevantes
  resultado = extrairMensagemPrincipal(resultado);

  // Etapa 3: Limpa caracteres de formatação indesejados
  resultado = limparCaracteresEspeciais(resultado);

  // Etapa 4: Padronização final e remoção de espaços excessivos
  resultado = resultado
    .replace(/\s+/g, ' ')                 // Normaliza espaços
    .replace(/^[\"",\s]+|[\"",\s]+$/g, '') // Remove aspas/vírgulas/espaços no início e fim
    .trim();

  return resultado;
}

/**
 * Remove metadados técnicos e estruturas JSON desnecessárias
 * @param {string} str - Texto contendo potenciais metadados
 * @return {string} - Texto sem estruturas de metadados
 */
function removerMetadataTecnico(str) {
  return str
    // Remoção de objetos de metadados específicos
    .replace(/\"response_metadata\"\s*:\s*{[^}]*}/g, '')
    .replace(/\"additional_kwargs\"\s*:\s*{[^}]*}/g, '')
    .replace(/\"tool_calls\"\s*:\s*\[[^\]]*]/g, '')
    .replace(/\"invalid_tool_calls\"\s*:\s*\[[^\]]*]/g, '')
    .replace(/\"type\"\s*:\s*\"(ai|human)\"/g, '')
    .replace(/\"data\"\s*:\s*{[^}]*}/g, '')

    // Limpeza de fragmentos JSON restantes
    .replace(/,\s*{[^}]*}/g, '')  // Objetos soltos após vírgula
    .replace(/,\s*\[\s*]/g, '')  // Arrays vazios após vírgula
    .replace(/\s*:\s*null/g, '') // Propriedades com valor null
    .replace(/\s*:\s*\[\]/g, '') // Propriedades com array vazio
    .replace(/\s*:\s*{}/g, '')   // Propriedades com objeto vazio

    // Normalização de espaços
    .replace(/\s+/g, ' ')
    .replace(/^\s+|\s+$/g, '');
}

const input = $input.all();
const body = input[0]?.json?.body || {};

const ticketData = body.ticket || {};
const msg = body.msg || {};

// 1. Número do contato: tenta msg.from, se não tiver usa o ticket.contact.number
const numeroContato =
  msg.from
  || ticketData.contact?.number
  || "";

// 2. Texto/conteúdo da mensagem
const texto =
  msg.text?.body
  || msg.image?.caption
  || msg.document?.caption
  || msg.body
  || "";

// 3. Mídia (id ou url)
const mediaId =
  msg.audio?.id
  || msg.image?.id
  || msg.document?.id
  || msg.mediaUrl
  || "";

// 4. Tipo de conteúdo
const tipoConteudo =
  msg.type
  || msg.mediaType
  || "text";

// 5. ID da mensagem
const idMensagem =
  msg.id
  || msg.messageId
  || "";

const nomeInstanciaReal = ticketData.whatsapp?.name || "";

// 🔒 Filtro atualizado: aceita mensagens recebidas (message) e enviadas (message_sent)
const metodosAceitos = ["message", "message_sent", "message_sent_waba"];

if (nomeInstanciaReal !== "FD Veículos - WABA" || !metodosAceitos.includes(body.method)) {
  return [];
}

// 6. Retorno refinado
return [{
  json: {
    idChat: numeroContato ? `${numeroContato}@s.whatsapp.net` : null,
    pushName: ticketData.contact?.name || "Cliente",
    conteudoMensagem: texto,
    idMensagem,
    timestamp: Math.floor(Date.now() / 1000),
    intervencaoMensagem: "outro",
    tipoConteudo,
    urlConteudo: mediaId,
    apikeyInstancia: ticketData.whatsapp?.tokenAPI || "",
    nomeInstancia: nomeInstanciaReal
  }
}];

// Remove marcadores internos do texto antes de enviar ao cliente (Parser/WhatsApp)
const out = String($json.agent_output ?? '');

// Remove o evento (linha inteira) e normaliza quebras de linha
const limpo = out
  .replace(/^\s*__MK_EVENT:(SIMULACAO|AGENDAMENTO)__\s*$/gmi, '')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

return [{ json: { ...$json, output: limpo } }];

// Normaliza a parte pra dedupe (minimiza diferenças bobas)
const raw = String($json.conteudo_whatsapp ?? '');
const normalized = raw
  .replace(/\r/g, '')
  .replace(/[ \t]+/g, ' ')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

// hash simples (sem libs)
function hash(str) {
  let h = 0;
  for (let i = 0; i < str.length; i++) {
    h = ((h << 5) - h) + str.charCodeAt(i);
    h |= 0;
  }
  return String(h);
}

const idChat = String($('Organiza Dados').item.json.idChat ?? '').trim();
const partHash = hash(normalized);

// chave única por chat + conteúdo da parte
const dedupKey = `mk-wpp:${idChat}_sent:${partHash}`;

return [{
  json: {
    ...$json,
    Mensagem: normalized,   // opcional: já devolve limpinha
    dedupKey
  }
}];

