    .replace(/\\t/g, "\t");

  // 2) Normaliza quebras (Windows/Mac)
  t = t.replace(/\r\n/g, "\n").replace(/\r/g, "\n");

  // 3) Remove caracteres invisíveis que quebram link (zero-width / BOM)
  t = t.replace(/[\u200B-\u200D\uFEFF]/g, "");

  // 4) URL sempre sozinha na linha (evita o "2" virar parte do link)
  t = t.replace(/(https?:\/\/[^\s]+)/g, "\n$1\n");

  // 5) Limpeza final: espaços antes de quebra + muitas quebras
  t = t
    .replace(/[ \t]+\n/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();

  // 6) IMPORTANTÍSSIMO: quebra final pra não colar no próximo item do loop
  return t + "\n";
})()
}}

