// Pega todos os itens que vieram do Split Out
const items = $input.all();

const seen = new Set();
const result = [];

for (const item of items) {
  const texto = (item.json.conteudo_whatsapp || '').trim();

  // Ignora vazios
  if (!texto) continue;

  // Se já vimos exatamente esse texto, pula
  if (seen.has(texto)) continue;

  // Marca como visto e mantém o item
  seen.add(texto);
  result.push(item);
}

return result;

// 1. Captura a saída do Agente (ajuste 'output' se o nome do campo for diferente)
const respostaBruta = $input.item.json.output || $input.item.json.text || "";

// 2. Divide o texto por parágrafos (onde houver 2 ou mais quebras de linha)
// Isso separa os "balões" de mensagem de forma humana.
const blocos = respostaBruta.split(/\n\n+/).filter(item => item.trim().length > 0);

// 3. Formata para o n8n enviar um item por mensagem
return blocos.map(mensagem => {
  return {
    json: {
      conteudo_whatsapp: mensagem.trim()
    }
  };
});
